2	import { Slot } from 'expo-router';
3	import { GestureHandlerRootView } from 'react-native-gesture-handler';
4	import { StatusBar } from 'expo-status-bar';
5	import { useFonts } from 'expo-font';
6	import * as SplashScreen from 'expo-splash-screen';
7	import { fontAssets } from '@/design/typography';
8	
9	// Hold the splash screen until custom fonts register — text with an unregistered
10	// fontFamily silently falls back to System on iOS and the swap is visible to the user.
11	// Promise rejects if the splash was already dismissed (fast-refresh, dev reloads) —
12	// swallow so Metro doesn't see an unhandled rejection.
13	SplashScreen.preventAutoHideAsync().catch(() => {});
14	
15	export default function RootLayout() {
16	  const [fontsLoaded, fontError] = useFonts(fontAssets);
17	
18	  useEffect(() => {
19	    if (fontsLoaded || fontError) {
20	      SplashScreen.hideAsync();
21	    }
22	  }, [fontsLoaded, fontError]);
23	
24	  if (!fontsLoaded && !fontError) {
25	    return null;
26	  }
27	
28	  return (
29	    <GestureHandlerRootView style={{ flex: 1 }}>
30	      <Slot />
31	      <StatusBar style="auto" />
32	    </GestureHandlerRootView>
33	  );
34	}
